import json
import ast

# Load data from file paths
books_path = var_functions.query_db:14
reviews_path = var_functions.query_db:18

with open(books_path, 'r') as f:
    try:
        books_data = json.load(f)
    except json.JSONDecodeError:
        f.seek(0)
        books_data = ast.literal_eval(f.read())

with open(reviews_path, 'r') as f:
    try:
        reviews_data = json.load(f)
    except json.JSONDecodeError:
        f.seek(0)
        reviews_data = ast.literal_eval(f.read())

# Extract numeric IDs for children's books
children_books_ids = set()
book_info = {}

for book in books_data:
    categories = book.get('categories', '')
    if categories and "Children's Books" in str(categories):
        book_id = book.get('book_id', '')
        if book_id and '_' in book_id:
            numeric_id = book_id.split('_')[1]
            children_books_ids.add(numeric_id)
            book_info[numeric_id] = {
                'book_id': book_id,
                'title': book.get('title', ''),
                'categories': categories
            }

# Process reviews (2020+)
reviews_by_book = {}

for review in reviews_data:
    review_time = review.get('review_time', '')
    if review_time >= '2020-01-01':
        purchase_id = review.get('purchase_id', '')
        if purchase_id and '_' in purchase_id:
            numeric_id = purchase_id.split('_')[1]
            if numeric_id in children_books_ids:
                rating = float(review.get('rating', 0))
                if numeric_id not in reviews_by_book:
                    reviews_by_book[numeric_id] = []
                reviews_by_book[numeric_id].append(rating)

# Calculate averages and filter
result_books = []

for numeric_id, ratings in reviews_by_book.items():
    if len(ratings) > 0:
        avg_rating = sum(ratings) / len(ratings)
        if avg_rating >= 4.5:
            book = book_info[numeric_id]
            result_books.append({
                'book_id': book['book_id'],
                'title': book['title'],
                'average_rating': round(avg_rating, 2),
                'review_count': len(ratings)
            })

# Sort by average rating descending
result_books.sort(key=lambda x: x['average_rating'], reverse=True)

# Print result
print('__RESULT__:')
print(json.dumps(result_books))

